const incoming = $input.first().json;
const body = incoming.body || incoming;

const required = ['study_field', 'location'];
const missing = required.filter(f => !body[f]);
if (missing.length > 0) {
  return [{ json: { ok: false, error: `Champs manquants: ${missing.join(', ')}`, missing, timestamp: new Date().toISOString() } }];
}

const locationParts = (body.location || '').split(',');
const city = (locationParts[0] || body.location).trim();
const country = (locationParts[1] || 'Tunisie').trim();

return [{ json: {
  ok: true,
  schedule: body.schedule || 'Non spécifié',
  studyField: body.study_field,
  location: body.location,
  city, country,
  skills: body.skills || 'Non spécifié',
  availabilityHours: body.availability_hours_per_week ?? 20,
  preferredType: body.preferred_job_type || 'les deux',
  language: body.language || 'fr',
  budget_needed: body.monthly_budget_needed ?? 600,
  ai_note: body.ai_note || '',
  timestamp: new Date().toISOString()
} }];

const studentData = $('Validate & Prepare Input').first().json;
const payloads = $input.all().map(i => i.json);
const nowISO = new Date().toISOString();

const stripHtml = (s='') => String(s).replace(/<[^>]*>/g,' ').replace(/\s+/g,' ').trim();
const normalKey = (s='') => stripHtml(s).toLowerCase().trim();
const hashKey  = (t,c,l) => `${normalKey(t)}|${normalKey(c)}|${normalKey(l)}`;

function hints(text='') {
  const t = normalKey(text);
  const h = [];
  if (/part.time|temps partiel/.test(t)) h.push('part-time');
  if (/flexible|flexibilit/.test(t)) h.push('flexible');
  if (/remote|télétravail|distance/.test(t)) h.push('remote');
  if (/evening|soir|night|nuit/.test(t)) h.push('evening');
  if (/weekend|samedi|dimanche/.test(t)) h.push('weekend');
  return h;
}

let jobs = [];

for (const data of payloads) {
  if (data?.results && Array.isArray(data.results)) {
    for (const j of data.results) {
      const desc = stripHtml(j.description || '');
      jobs.push({
        id: String(j.id || Math.random().toString(36).slice(2)),
        title: j.title || 'Titre non disponible',
        company: j.company?.display_name || 'Non mentionné',
        location: j.location?.display_name || studentData.location,
        job_type: 'Présentiel/Hybride',
        salary_display: (j.salary_min || j.salary_max) ? `${j.salary_min ?? ''} - ${j.salary_max ?? ''} EUR` : 'Non spécifié',
        description: desc.substring(0, 400),
        apply_url: j.redirect_url || '#',
        source: 'Adzuna',
        posted_date: j.created || nowISO,
        hour_hints: hints(desc)
      });
    }
  }
  if (data?.jobs && Array.isArray(data.jobs)) {
    for (const j of data.jobs) {
      const desc = stripHtml(j.description || '');
      jobs.push({
        id: String(j.id || Math.random().toString(36).slice(2)),
        title: j.title || 'Titre non disponible',
        company: j.company_name || 'Non mentionné',
        location: '🌍 Remote (Travail à distance)',
        job_type: 'Remote',
        salary_display: j.salary || 'Non spécifié',
        description: desc.substring(0, 400),
        apply_url: j.url || '#',
        source: 'Remotive',
        posted_date: j.publication_date || nowISO,
        hour_hints: hints(desc),
        tags: j.tags || []
      });
    }
  }
}

const seen = new Set();
const deduped = jobs.filter(j => {
  const k = hashKey(j.title, j.company, j.location);
  if (seen.has(k)) return false;
  seen.add(k);
  return true;
});

const prefType = (studentData.preferredType || 'les deux').toLowerCase();
let filtered = deduped;
if (prefType === 'remote') {
  filtered = deduped.filter(j => j.job_type.toLowerCase().includes('remote'));
} else if (prefType === 'présentiel' || prefType === 'presentiel') {
  filtered = deduped.filter(j => !j.job_type.toLowerCase().includes('remote'));
}

return [{ json: { jobs: filtered, studentData, totalFound: filtered.length } }];

const d = $input.first().json;
const sd = d.studentData;

const systemMsg = 'Tu es un expert en emploi étudiant. Réponds UNIQUEMENT en JSON valide sans markdown ni backticks. Sois précis et bienveillant.';

const userMsg = `Profil étudiant:
- Domaine: ${sd.studyField}
- Lieu: ${sd.location}
- Emploi du temps: ${sd.schedule}
- Compétences: ${sd.skills}
- Disponibilité: ${sd.availabilityHours}h/semaine
- Budget cible: ${sd.budget_needed} TND/mois
- Type souhaité: ${sd.preferredType}
- Note personnelle: ${sd.ai_note || 'aucune'}

Nombre d'offres trouvées: ${d.totalFound}
Données offres: ${JSON.stringify(d.jobs.slice(0,25))}

Retourne ce JSON valide sans markdown:
{
  "filtered_jobs": [
    {
      "rank": 1,
      "title": "titre exact",
      "company": "entreprise",
      "location": "ville",
      "job_type": "Remote|Présentiel|Hybride",
      "working_hours": "horaires ou Non spécifié",
      "hours_per_week": "20h",
      "salary": "montant ou Non spécifié",
      "apply_url": "url exacte de l'offre",
      "source": "plateforme source",
      "compatibility_score": 85,
      "why_compatible": "raison courte max 15 mots",
      "required_skills": ["skill1", "skill2"],
      "tips": "conseil personnalisé max 20 mots"
    }
  ],
  "total_results": 5,
  "summary": "résumé des résultats en 2 phrases max",
  "additional_platforms": [
    {"name": "LinkedIn Jobs", "url": "https://www.linkedin.com/jobs/", "description": "Jobs étudiant et stages"},
    {"name": "Tanitjobs.com", "url": "https://www.tanitjobs.com", "description": "Offres en Tunisie"},
    {"name": "OptionCarrière", "url": "https://www.optioncarriere.tn", "description": "Agrégateur Tunisie"},
    {"name": "Upwork", "url": "https://www.upwork.com", "description": "Freelance international"},
    {"name": "Remotive.com", "url": "https://www.remotive.com", "description": "Jobs remote uniquement"}
  ]
}`;

const groqPayload = {
  model: 'llama-3.3-70b-versatile',
  max_tokens: 4000,
  temperature: 0.2,
  messages: [
    { role: 'system', content: systemMsg },
    { role: 'user',   content: userMsg }
  ]
};

return [{ json: { groqPayload, studentData: sd } }];

const ai = $input.first().json;
const studentData = $('Validate & Prepare Input').first().json;

const raw = ai?.choices?.[0]?.message?.content || '';

let parsed = null;
try {
  const clean = String(raw).replace(/```json\s*/gi,'').replace(/```\s*/g,'').trim();
  parsed = clean ? JSON.parse(clean) : null;
} catch(e) {
  parsed = null;
}

if (!parsed || typeof parsed !== 'object') {
  parsed = { filtered_jobs: [], total_results: 0, summary: 'Analyse IA temporairement indisponible.', additional_platforms: [] };
}

const offers = Array.isArray(parsed.filtered_jobs) ? parsed.filtered_jobs : [];

const finalOutput = {
  success: true,
  generated_at: new Date().toISOString(),
  ai_model: 'Groq llama-3.3-70b-versatile',
  student_profile: {
    study_field: studentData.studyField,
    location: studentData.location,
    schedule: studentData.schedule,
    skills: studentData.skills,
    availability: `${studentData.availabilityHours} heures/semaine`,
    preferred_type: studentData.preferredType,
    budget_needed: `${studentData.budget_needed} TND/mois`
  },
  results: {
    total_jobs_found: parsed.total_results || offers.length,
    summary: parsed.summary || '',
    job_offers: offers.map((job, idx) => ({
      rank: job.rank ?? (idx + 1),
      title: job.title,
      company: job.company,
      location: job.location,
      job_type: job.job_type,
      working_hours: {
        schedule: job.working_hours || 'Non spécifié',
        hours_per_week: job.hours_per_week || 'Non spécifié'
      },
      compensation: {
        amount: job.salary || 'Non spécifié',
        period: 'par mois'
      },
      apply: {
        url: job.apply_url,
        source_platform: job.source
      },
      compatibility: {
        score: job.compatibility_score ?? null,
        reason: job.why_compatible || ''
      },
      required_skills: job.required_skills || [],
      personalized_tip: job.tips || ''
    })),
    additional_platforms: parsed.additional_platforms?.length ? parsed.additional_platforms : [
      { name: 'LinkedIn Jobs',     url: 'https://www.linkedin.com/jobs/', description: 'Jobs étudiant, stages, part-time' },
      { name: 'Tanitjobs.com',     url: 'https://www.tanitjobs.com',      description: 'Offres en Tunisie' },
      { name: 'OptionCarrière',    url: 'https://www.optioncarriere.tn',  description: 'Agrégateur offres Tunisie' },
      { name: 'Upwork',            url: 'https://www.upwork.com',         description: 'Freelance international remote' },
      { name: 'Remotive.com',      url: 'https://www.remotive.com',       description: 'Jobs remote uniquement' }
    ]
  }
};

return [{ json: finalOutput }];

// CAREER ADVISOR ENDPOINT
const body = $input.first().json.body || $input.first().json;

const message = body.message || '';
const profile = body.profile || {};
const jobsFound = body.jobs_found || 0;

const systemMsg = `Tu es un conseiller carrière expert pour étudiants tunisiens. 
Tu connais le marché du travail local et international.
Tu donnes des conseils concrets, bienveillants et actionnables.
Réponds en français de manière directe et structurée.
Max 200 mots par réponse.`;

const userMsg = `Profil étudiant: domaine=${profile.study_field||'Non spécifié'}, lieu=${profile.location||'Tunisie'}, compétences=${profile.skills||'Non spécifié'}
Offres trouvées: ${jobsFound}

Question: ${message}`;

const groqPayload = {
  model: 'llama-3.3-70b-versatile',
  max_tokens: 500,
  temperature: 0.7,
  messages: [
    { role: 'system', content: systemMsg },
    { role: 'user',   content: userMsg }
  ]
};

return [{ json: { groqPayload } }];

const ai = $input.first().json;
const reply = ai?.choices?.[0]?.message?.content || 'Je suis là pour t\'aider avec ta carrière !';

return [{ json: {
  success: true,
  reply: reply,
  timestamp: new Date().toISOString()
} }];
